import{C as e,o as t,c as l,a5 as a,E as p}from"./chunks/framework.CW28V7p_.js";const d=JSON.parse('{"title":"1. Transaction anatomy","description":"","frontmatter":{},"headers":[],"relativePath":"module-3/1-tx-anatomy.md","filePath":"module-3/1-tx-anatomy.md","lastUpdated":1780937944000}'),o={name:"module-3/1-tx-anatomy.md"},u=Object.assign(o,{setup(r){const n={id:"m3-1-tx-anatomy",title:"🧠 Mini-check: Transaction anatomy",intro:"3 питання — TX structure.",questions:[{type:"mcq",q:"Що з цього є частинами Solana transaction? (обери всі)",options:["Список signatures (signed by accounts that authorize)","Список accounts (всі accounts які TX буде читати/писати)","Recent blockhash (для expiry tracking)","Список instructions (що робити)","Gas limit і gas price"],correct:[0,1,2,3],explanation:"Tx має: signatures, account list, recent blockhash, instructions. Gas limit/price = Ethereum terminology — Solana використовує compute budget + priority fees, але структура іnша. Module 3.1."},{type:"explain",q:"Чому Solana TX вимагає список ВСІХ accounts які буде touched, заздалегідь?",ideal:`Це enabler для Sealevel parallelism. Runtime scheduler читає account lists з усіх pending TX і визначає які TX можуть виконуватись паралельно (touch different accounts) vs sequentially (touch same accounts → потенційний conflict).

Без pre-declared lists scheduler не може зробити цей analysis — мусив би виконувати TXs sequentially або race-detect on-the-fly (повільно). Solana вибрала pre-declaration: developer/SDK сам формує список, runtime просто планує.

Tradeoffs:
+ Massive parallelism — десятки TXs паралельно
- TX size зростає (кожен account =32 bytes у TX)
- Developer mental overhead — must know all accounts upfront

Це fundamental з 'rules of the game' для Solana smart contracts.`,explanation:"Pre-declared accounts = parallelism enabler. Module 3.1."},{type:"command",q:"Як подивитись detailed info про конкретну TX за її signature? Напиши команду.",accepts:["solana confirm -v <SIGNATURE>","solana confirm -v <SIGNATURE> --url mainnet-beta","solana confirm <SIGNATURE>"],ideal:"solana confirm -v <SIGNATURE>",explanation:"solana confirm <SIG> — статус (confirmed/finalized/failed). -v = verbose: instructions, accounts, logs, compute units used. Module 3.1."}]};return(c,s)=>{const i=e("Quiz");return t(),l("div",null,[s[0]||(s[0]=a("",69)),p(i,{data:n}),s[1]||(s[1]=a("",6))])}}});export{d as __pageData,u as default};
